const now = new Date();

const tehranNow = new Date(
  now.toLocaleString('en-US', { timeZone: 'Asia/Tehran' })
);

const jsDay = tehranNow.getDay();
const daysSinceSaturday = (jsDay + 1) % 7;

const weekStart = new Date(tehranNow);
weekStart.setDate(tehranNow.getDate() - daysSinceSaturday);
weekStart.setHours(0, 0, 0, 0);

const fmt = (d) => {
  const y = d.getFullYear();
  const m = String(d.getMonth() + 1).padStart(2, '0');
  const day = String(d.getDate()).padStart(2, '0');
  return `${y}-${m}-${day}`;
};

const fmtJalali = (d) => {
  return new Intl.DateTimeFormat('fa-IR-u-ca-persian', {
    year: 'numeric',
    month: '2-digit',
    day: '2-digit',
  }).format(d);
};

return [
  {
    json: {
      target_week_start: fmt(weekStart),
      target_week_start_jalali: fmtJalali(weekStart),
    },
  },
];

const daysOrder = ['شنبه', 'یکشنبه', 'دوشنبه', 'سه شنبه', 'چهارشنبه', 'پنج شنبه'];

const weekMenu = $('Get Week Menu For Employees').all().map(i => i.json);
const reservations = $('Get User Weekly Reservations').all().map(i => i.json);
const targetWeekStart = $('Get Target Week Start').item.json.target_week_start;

const now = new Date();
const tehranNow = new Date(now.toLocaleString('en-US', { timeZone: 'Asia/Tehran' }));
const currentHour = tehranNow.getHours();

const jsDayToFa = ['یکشنبه', 'دوشنبه', 'سه شنبه', 'چهارشنبه', 'پنج شنبه', 'جمعه', 'شنبه'];
const todayFa = jsDayToFa[tehranNow.getDay()];

const dayIndexMap = {
  'شنبه': 0,
  'یکشنبه': 1,
  'دوشنبه': 2,
  'سه شنبه': 3,
  'چهارشنبه': 4,
  'پنج شنبه': 5,
  'جمعه': 6
};

const todayIndex = dayIndexMap[todayFa];

const dayMap = {
  0: 1, // Sunday -> یکشنبه
  1: 2, // Monday -> دوشنبه
  2: 3, // Tuesday -> سه شنبه
  3: 4, // Wednesday -> چهارشنبه
  4: 5, // Thursday -> پنج شنبه
  5: 6, // Friday -> جمعه
  6: 0  // Saturday -> شنبه
};

const currentFaDayIndex = dayMap[tehranNow.getDay()];

const startOfCurrentWeek = new Date(tehranNow);
startOfCurrentWeek.setDate(tehranNow.getDate() - currentFaDayIndex);
startOfCurrentWeek.setHours(0, 0, 0, 0);

const fmt = (d) => {
  const y = d.getFullYear();
  const m = String(d.getMonth() + 1).padStart(2, '0');
  const day = String(d.getDate()).padStart(2, '0');
  return `${y}-${m}-${day}`;
};

const currentWeekStartStr = fmt(startOfCurrentWeek);
const isNextWeek = targetWeekStart !== currentWeekStartStr;

const menuMap = {};
for (const row of weekMenu) {
  menuMap[row.day_of_week] = row;
}

const reservationMap = {};
for (const row of reservations) {
  reservationMap[row.day_of_week] = row;
}

function getTomorrowFa() {
  const tomorrow = new Date(tehranNow);
  tomorrow.setDate(tomorrow.getDate() + 1);
  return jsDayToFa[tomorrow.getDay()];
}

function getDayStatus(day) {
  if (!menuMap[day]) {
    return 'no_menu';
  }

  if (isNextWeek) {
    return 'active';
  }

  const idx = dayIndexMap[day];
  const tomorrowFa = getTomorrowFa();

  if (idx < todayIndex) {
    return 'past';
  }

  if (idx === todayIndex) {
    return 'today';
  }

  if (day === tomorrowFa && currentHour >= 19) {
    return 'tomorrow_closed';
  }

  return 'active';
}

const rows = [];

for (const day of daysOrder) {
  const status = getDayStatus(day);
  const reserve = reservationMap[day];

  let text = day;
  let callback_data = `select_reserve_day|${day}`;

  if (status === 'past') {
    text = `⚪️ ${day} - گذشته`;
    callback_data = `ignore_day|${day}`;
  } else if (status === 'today') {
    text = `⛔️ ${day} - بسته`;
    callback_data = `ignore_day|${day}`;
  } else if (status === 'tomorrow_closed') {
    text = `⏰ ${day} - بسته`;
    callback_data = `ignore_day|${day}`;
  } else if (status === 'no_menu') {
    text = `📭 ${day} - بدون منو`;
    callback_data = `ignore_day|${day}`;
  } else {
    if (reserve) {
      text = `✅ ${day} - ${reserve.food} (${reserve.portion_label || 'پرس کامل'})`;
    } else {
      text = `🍽 ${day}`;
    }
  }

  rows.push([{ text, callback_data }]);
}

return [
  {
    json: {
      chat_id: $('Telegram Trigger').item.json.callback_query.message.chat.id,
      text: isNextWeek
        ? '🍽 رزرو غذای هفتگی (هفته بعد)\n\nلطفاً روز موردنظر را انتخاب کنید:'
        : '🍽 رزرو غذای هفتگی\n\nلطفاً روز موردنظر را انتخاب کنید:',
      reply_markup: {
        inline_keyboard: rows
      }
    }
  }
];

const menu = $('Get Selected Day Menu').first().json;
const reservation = $('Get Selected Day Reservation').first().json || {};
const day = menu.day_of_week;

const foodOptions = [
  { slot: 'f1', title: menu.food1 },
  { slot: 'f2', title: menu.food2 },
  { slot: 'f3', title: menu.food3 },
].filter((item) => item.title && String(item.title).trim());

const rows = foodOptions.map((item) => [
  {
    text: `🍽 ${item.title}`,
    callback_data: `choose_food_portion|${day}|${item.slot}`,
  },
]);

if (reservation.food) {
  rows.push([
    {
      text: '❌ لغو رزرو',
      callback_data: `cancel_reservation|${day}`,
    },
  ]);
}

rows.push([{ text: '🔙 بازگشت', callback_data: 'food_booking|menu' }]);

const currentReservationText = reservation.food
  ? `✅ رزرو فعلی شما: ${reservation.food}${reservation.portion_label ? ` - ${reservation.portion_label}` : ''}`
  : 'هنوز رزروی ثبت نشده است.';

const foodsText = foodOptions
  .map((item, index) => `${index + 1}️⃣ ${item.title}`)
  .join('\n');

return [
  {
    json: {
      chat_id: $('Telegram Trigger').item.json.callback_query.message.chat.id,
      text: `🍽 رزرو روز ${day}

لطفاً غذای موردنظر را انتخاب کنید:

${foodsText}

${currentReservationText}`,
      reply_markup: {
        inline_keyboard: rows,
      },
    },
  },
];

